solution:
INTERLIS 2.4;

MODEL OwnershipModel (de) AT "https://example.com" VERSION "2026-05-19" =
  TOPIC Data =
    CLASS Person =
      Name : TEXT*100;
    END Person;

    CLASS Building =
      Name : TEXT*100;
    END Building;

    ASSOCIATION Ownership =
      owner -- {0..*} Person;
      building -- {0..*} Building;
    END Ownership;
  END Data;
END OwnershipModel.
